    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<ApplicationUser>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Email).IsUnique(); b.Property(x => x.Email).HasMaxLength(256); b.Property(x => x.FullName).HasMaxLength(256); b.Property(x => x.PhoneNumber).HasMaxLength(64); b.Property(x => x.UserType).HasConversion<string>().HasMaxLength(64); b.Property(x => x.PasswordHash).HasMaxLength(1024); b.HasMany(x => x.UserRoles).WithOne().HasForeignKey(x => x.UserId).OnDelete(DeleteBehavior.Cascade); b.HasOne(x => x.Profile).WithOne().HasForeignKey<UserProfile>(x => x.UserId).OnDelete(DeleteBehavior.Cascade); b.HasOne(x => x.SupplierLink).WithOne().HasForeignKey<SupplierUserLink>(x => x.UserId).OnDelete(DeleteBehavior.Cascade); });
        modelBuilder.Entity<Role>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Name).IsUnique(); b.Property(x => x.Name).HasMaxLength(128); b.Property(x => x.Description).HasMaxLength(512); b.HasMany(x => x.RolePermissions).WithOne().HasForeignKey(x => x.RoleId).OnDelete(DeleteBehavior.Cascade); b.HasMany(x => x.UserRoles).WithOne().HasForeignKey(x => x.RoleId).OnDelete(DeleteBehavior.Cascade); });
        modelBuilder.Entity<Permission>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Code).IsUnique(); b.Property(x => x.Code).HasMaxLength(128); b.Property(x => x.Name).HasMaxLength(256); b.Property(x => x.Description).HasMaxLength(512); b.Property(x => x.Category).HasMaxLength(128); b.HasMany(x => x.RolePermissions).WithOne().HasForeignKey(x => x.PermissionId).OnDelete(DeleteBehavior.Cascade); });
        modelBuilder.Entity<RolePermission>(b => { b.HasKey(x => x.Id); b.HasIndex(x => new { x.RoleId, x.PermissionId }).IsUnique(); });
        modelBuilder.Entity<UserRole>(b => { b.HasKey(x => x.Id); b.HasIndex(x => new { x.UserId, x.RoleId }).IsUnique(); });
        modelBuilder.Entity<UserProfile>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.UserId).IsUnique(); b.Property(x => x.Department).HasMaxLength(128); b.Property(x => x.JobTitle).HasMaxLength(128); b.Property(x => x.PreferencesJson).HasColumnType("nvarchar(max)"); });
        modelBuilder.Entity<SupplierUserLink>(b => { b.HasKey(x => x.Id); b.HasIndex(x => new { x.UserId, x.SupplierId }).IsUnique(); });


        modelBuilder.Entity<ApiPerformanceSample>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.OccurredAt); b.HasIndex(x => x.StatusCode); b.Property(x => x.CorrelationId).HasMaxLength(128); b.Property(x => x.Path).HasMaxLength(512); b.Property(x => x.Method).HasMaxLength(16); b.Property(x => x.UserId).HasMaxLength(256); });
        modelBuilder.Entity<BackupPlan>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Code).IsUnique(); b.Property(x => x.Code).HasMaxLength(128); b.Property(x => x.Name).HasMaxLength(256); b.Property(x => x.BackupType).HasConversion<string>().HasMaxLength(64); b.Property(x => x.ScheduleDescription).HasMaxLength(512); b.Property(x => x.StorageLocation).HasMaxLength(512); b.Property(x => x.CreatedBy).HasMaxLength(256); });
        modelBuilder.Entity<BackupRun>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.StartedAt); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(64); b.Property(x => x.BackupReference).HasMaxLength(512); b.Property(x => x.ErrorMessage).HasMaxLength(2000); b.Property(x => x.TriggeredBy).HasMaxLength(256); });
        modelBuilder.Entity<RestoreRun>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.StartedAt); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(64); b.Property(x => x.RestoreTarget).HasMaxLength(512); b.Property(x => x.ErrorMessage).HasMaxLength(2000); b.Property(x => x.TriggeredBy).HasMaxLength(256); });
        modelBuilder.Entity<SupportCase>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.CaseNumber).IsUnique(); b.HasIndex(x => x.Status); b.Property(x => x.CaseNumber).HasMaxLength(64); b.Property(x => x.Title).HasMaxLength(256); b.Property(x => x.Description).HasMaxLength(4000); b.Property(x => x.Severity).HasConversion<string>().HasMaxLength(64); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(64); b.Property(x => x.Module).HasMaxLength(128); b.Property(x => x.ReportedBy).HasMaxLength(256); b.Property(x => x.AssignedTo).HasMaxLength(256); b.Property(x => x.ResolutionNotes).HasMaxLength(4000); b.Property(x => x.CorrelationId).HasMaxLength(128); });
        modelBuilder.Entity<UserMfaSetting>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.UserId).IsUnique(); b.Property(x => x.PreferredMethod).HasConversion<string>().HasMaxLength(64); b.Property(x => x.AuthenticatorSecretEncrypted).HasMaxLength(2048); });
        modelBuilder.Entity<UserMfaChallenge>(b => { b.HasKey(x => x.Id); b.Property(x => x.Method).HasConversion<string>().HasMaxLength(64); b.Property(x => x.CodeHash).HasMaxLength(512); });
        modelBuilder.Entity<TrustedDevice>(b => { b.HasKey(x => x.Id); b.HasIndex(x => new { x.UserId, x.DeviceHash }).IsUnique(); b.Property(x => x.DeviceHash).HasMaxLength(512); b.Property(x => x.Name).HasMaxLength(256); });
        modelBuilder.Entity<IdentityProviderConfiguration>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Code).IsUnique(); b.Property(x => x.Code).HasMaxLength(128); b.Property(x => x.Name).HasMaxLength(256); b.Property(x => x.ProviderType).HasConversion<string>().HasMaxLength(64); b.Property(x => x.ClientSecretEncrypted).HasMaxLength(2048); b.Property(x => x.SettingsJson).HasColumnType("nvarchar(max)"); });
        modelBuilder.Entity<ExternalIdentityLink>(b => { b.HasKey(x => x.Id); b.HasIndex(x => new { x.ProviderCode, x.ExternalSubjectId }).IsUnique(); b.Property(x => x.ProviderCode).HasMaxLength(128); b.Property(x => x.ExternalSubjectId).HasMaxLength(512); });
        modelBuilder.Entity<DelegationRule>(b => { b.HasKey(x => x.Id); b.Property(x => x.RoleCode).HasMaxLength(128); b.Property(x => x.Reason).HasMaxLength(1000); b.Property(x => x.CreatedBy).HasMaxLength(256); });
        modelBuilder.Entity<EscalationRule>(b => { b.HasKey(x => x.Id); b.Property(x => x.EntityType).HasMaxLength(128); b.Property(x => x.WorkflowCode).HasMaxLength(128); b.Property(x => x.NodeCode).HasMaxLength(128); b.Property(x => x.AssignedRole).HasMaxLength(128); b.Property(x => x.EscalateToRole).HasMaxLength(128); });
        modelBuilder.Entity<WorkflowTaskEscalation>(b => { b.HasKey(x => x.Id); b.Property(x => x.EscalatedToRole).HasMaxLength(128); b.Property(x => x.Reason).HasMaxLength(1000); });

        modelBuilder.Entity<NotificationTemplate>(b => { b.HasKey(x => x.Id); b.HasIndex(x => x.Code).IsUnique(); b.Property(x => x.Code).HasMaxLength(128); b.Property(x => x.Name).HasMaxLength(256); b.Property(x => x.Description).HasMaxLength(2000); b.Property(x => x.EventCode).HasMaxLength(128); b.Property(x => x.Channel).HasConversion<string>().HasMaxLength(32); b.Property(x => x.SubjectTemplate).HasMaxLength(512); b.Property(x => x.BodyTemplate).HasColumnType("nvarchar(max)"); });
        modelBuilder.Entity<NotificationMessage>(b => { b.HasKey(x => x.Id); b.Property(x => x.EventCode).HasMaxLength(128); b.Property(x => x.EntityType).HasMaxLength(128); b.Property(x => x.Channel).HasConversion<string>().HasMaxLength(32); b.Property(x => x.Subject).HasMaxLength(512); b.Property(x => x.Body).HasColumnType("nvarchar(max)"); b.Property(x => x.Priority).HasConversion<string>().HasMaxLength(32); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(32); b.Property(x => x.FailureReason).HasMaxLength(2000); b.Property(x => x.RelatedUrl).HasMaxLength(512); b.HasMany(x => x.Recipients).WithOne().HasForeignKey(x => x.NotificationMessageId).OnDelete(DeleteBehavior.Cascade); });
        modelBuilder.Entity<NotificationRecipient>(b => { b.HasKey(x => x.Id); b.Property(x => x.UserId).HasMaxLength(256); b.Property(x => x.RecipientType).HasMaxLength(64); b.Property(x => x.Name).HasMaxLength(256); b.Property(x => x.Email).HasMaxLength(256); b.Property(x => x.PhoneNumber).HasMaxLength(64); b.Property(x => x.RoleCode).HasMaxLength(128); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(32); });
        modelBuilder.Entity<NotificationDeliveryLog>(b => { b.HasKey(x => x.Id); b.Property(x => x.Channel).HasConversion<string>().HasMaxLength(32); b.Property(x => x.RequestPayload).HasColumnType("nvarchar(max)"); b.Property(x => x.ResponsePayload).HasColumnType("nvarchar(max)"); b.Property(x => x.Status).HasConversion<string>().HasMaxLength(32); b.Property(x => x.Error).HasMaxLength(2000); });
